 71→  if (!job.artifacts) {
 72→    return "Artefakt ist noch nicht verfügbar.";
 73→  }
 74→
 75→  switch (view) {
 76→    case "markdown":
 77→      return job.artifacts.markdown;
 78→    case "handover":
 79→      return job.artifacts.handover;
 80→    case "json":
 81→      return job.artifacts.json;
