176→    (messageId: string) => {
177→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
178→      const preview =
179→        msg?.blocks
180→          .map((b) => ("text" in b ? b.text : b.type))
181→          .join(" ")
182→          .slice(0, 200) ?? messageId;
183→      setDeleteDialog({ messageId, isRound: true, preview });
184→    },
185→    [job.conversation?.messages],
186→  );
