193→      if (isRound) {
194→        const result = await deletion.deleteRound(messageId, reason);
195→        deletionToast.showDeletedToast(messageId, true, result.length);
196→      } else {
197→        await deletion.deleteMessage(messageId, reason);
198→        deletionToast.showDeletedToast(messageId, false);
199→      }
200→    },
201→    [deleteDialog, deletion, deletionToast],
202→  );
203→
204→  const handleUndoDelete = useCallback(async () => {
205→    if (!deletionToast.toast) return;
206→    await deletion.restoreMessage(deletionToast.toast.messageId);
207→    deletionToast.dismissToast();
208→  }, [deletion, deletionToast]);
209→
210→  const mergedRef = useCallback(
211→    (node: HTMLElement | null) => {
212→      (
213→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
214→      ).current = node;
215→      (
216→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
217→      ).current = node;
218→    },
219→    [session.sectionRef, popover.containerRef],
220→  );
221→
222→  const artifact = view === "reader" ? "" : renderArtifact(view, job);
223→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
224→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
225→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
226→  const displayedMarkdown = useMemo(() => {
227→    if (view !== "markdown") return artifact;
228→    try {
229→      return applyMarkdownRules(artifact, rules.activeRules);
230→    } catch {
231→      return artifact;
232→    }
233→  }, [artifact, rules.activeRules, view]);
234→
235→  const resolvedConversation = useMemo(() => {
236→    if (!job.conversation) return undefined;
237→    return {
238→      ...job.conversation,
239→      messages: resolvedMessages.map((rm) => ({
240→        id: rm.id,
241→        role: rm.role,
242→        blocks: rm.blocks,
243→      })),
244→    };
245→  }, [job.conversation, resolvedMessages]);
246→
247→  const readerEffectsMap = useMemo(
248→    () =>
249→      view === "reader" && resolvedConversation
250→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
251→        : new Map(),
252→    [rules.activeRules, resolvedConversation, view],
253→  );
254→
255→  const handleCopyMessage = useCallback(
256→    (messageId: string) => {
257→      const msg = resolvedConversation?.messages.find(
258→        (m) => m.id === messageId,
259→      );
260→      if (!msg) return;
261→      void copyMessageToClipboard(msg, view, msg.blocks);
262→    },
263→    [resolvedConversation, view],
264→  );
265→
266→  const [copySuccess, setCopySuccess] = useState(false);
267→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
268→
269→  const handleCopyAll = useMemo(() => {
270→    const doCopy = async (content: string, isHtml: boolean) => {
271→      try {
272→        if (isHtml) {
273→          const blob = new Blob([content], { type: "text/html" });
274→          const plainBlob = new Blob([content], { type: "text/plain" });
275→          await navigator.clipboard.write([
276→            new ClipboardItem({
277→              "text/html": blob,
278→              "text/plain": plainBlob,
279→            }),
280→          ]);
281→        } else {
282→          await navigator.clipboard.writeText(content);
283→        }
284→        clearTimeout(copyTimeoutRef.current);
285→        setCopySuccess(true);
286→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
287→      } catch {
288→        // Fallback: silently fail
289→      }
290→    };
291→
292→    if (view === "markdown") {
293→      return () => {
294→        void doCopy(displayedMarkdown, false);
295→      };
296→    }
297→    if (view === "reader" && resolvedConversation) {
298→      return () => {
299→        const html = buildReaderHtml(
300→          resolvedConversation,
301→          readerEffectsMap,
302→          resolvedConversation.title ?? `export-${job.id}`,
303→        );
304→        void doCopy(html, true);
305→      };
306→    }
307→    if ((view === "handover" || view === "json") && artifact) {
308→      return () => {
309→        void doCopy(artifact, false);
310→      };
311→    }
312→    return undefined;
313→  }, [
314→    view,
315→    displayedMarkdown,
316→    job.id,
317→    resolvedConversation,
318→    readerEffectsMap,
319→    artifact,
320→  ]);
321→
322→  const handleDownload = useMemo(() => {
323→    if (view === "markdown") {
324→      return () => {
325→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
326→        const url = URL.createObjectURL(blob);
327→        const a = document.createElement("a");
328→        a.href = url;
329→        a.download = `export-${job.id}.md`;
330→        document.body.appendChild(a);
331→        a.click();
332→        document.body.removeChild(a);
333→        setTimeout(() => URL.revokeObjectURL(url), 100);
334→      };
335→    }
336→    if (view === "reader" && resolvedConversation) {
337→      return () => {
338→        const html = buildReaderHtml(
339→          resolvedConversation,
340→          readerEffectsMap,
341→          resolvedConversation.title ?? `export-${job.id}`,
342→        );
343→        const blob = new Blob([html], { type: "text/html" });
344→        const url = URL.createObjectURL(blob);
345→        const a = document.createElement("a");
346→        a.href = url;
347→        a.download = `export-${job.id}.html`;
348→        document.body.appendChild(a);
349→        a.click();
350→        document.body.removeChild(a);
351→        setTimeout(() => URL.revokeObjectURL(url), 100);
352→      };
353→    }
354→    if ((view === "handover" || view === "json") && artifact) {
355→      return () => {
356→        const ext = view === "json" ? "json" : "md";
357→        const blob = new Blob([artifact], { type: "text/plain" });
358→        const url = URL.createObjectURL(blob);
359→        const a = document.createElement("a");
360→        a.href = url;
361→        a.download = `export-${job.id}.${ext}`;
362→        document.body.appendChild(a);
363→        a.click();
364→        document.body.removeChild(a);
365→        setTimeout(() => URL.revokeObjectURL(url), 100);
366→      };
367→    }
368→    return undefined;
369→  }, [
370→    view,
371→    displayedMarkdown,
372→    job.id,
373→    resolvedConversation,
374→    readerEffectsMap,
375→    artifact,
376→  ]);
377→  const showPopover =
378→    session.adjustModeEnabled &&
379→    Boolean(session.activeSelection) &&
380→    Boolean(session.activeAnchor);
381→
382→  const popoverCallbacksRef = useRef({
383→    handleDiscardSession: session.handleDiscardSession,
384→    activeSessionDetail: session.activeSessionDetail,
385→    handleRejectLastChange: rules.handleRejectLastChange,
386→    setReplyVisible: session.setReplyVisible,
387→  });
388→  popoverCallbacksRef.current = {
389→    handleDiscardSession: session.handleDiscardSession,
390→    activeSessionDetail: session.activeSessionDetail,
391→    handleRejectLastChange: rules.handleRejectLastChange,
392→    setReplyVisible: session.setReplyVisible,
393→  };
394→
395→  const handlePopoverClose = useCallback(() => {
396→    popoverCallbacksRef.current.handleDiscardSession();
397→  }, []);
398→
399→  const handleRejectLastChange = useCallback(() => {
400→    const {
401→      activeSessionDetail,
402→      handleRejectLastChange: reject,
403→      setReplyVisible,
404→    } = popoverCallbacksRef.current;
405→    if (activeSessionDetail) {
406→      void reject(activeSessionDetail).then((success) => {
407→        if (success) setReplyVisible(false);
408→      });
409→    }
410→  }, []);
411→
412→  const sessionError =
413→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
414→
415→  const viewErrorFallback = (_error: Error, reset: () => void) => (
416→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
417→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
418→      <button
419→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
420→        type="button"
421→        onClick={reset}
422→      >
423→        {miscLabels.retryButton}
424→      </button>
425→    </div>
426→  );
427→
428→  return (
429→    <section
430→      ref={mergedRef}
431→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
432→    >
433→      <StatusHeader
434→        activeStage={activeStage}
435→        elapsedTime={elapsedTime}
436→        job={job}
437→      />
438→
439→      {job.warnings.length > 0 ? (
440→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
441→          {job.warnings[0]}
442→        </div>
443→      ) : null}
444→
445→      {job.status === "failed" ? (
446→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
447→          <p className="font-medium">{miscLabels.importFailed}</p>
448→          {job.errorStage && job.errorStage !== "done" && (
449→            <p className="text-sm mt-1">
450→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
451→            </p>
452→          )}
453→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
454→        </div>
455→      ) : job.status === "queued" || job.status === "running" ? (
456→        <LoadingStateBlock stageDetail={activeStage?.detail} />
457→      ) : (
458→        <div className="space-y-4">
459→          <CompletedToolbar
460→            adjustModeEnabled={session.adjustModeEnabled}
461→            copySuccess={copySuccess}
462→            editMode={editMode}
463→            isAdjustableView={isAdjustableView}
464→            rules={rules}
465→            view={view}
466→            onCopyAll={handleCopyAll}
467→            onDownloadMarkdown={handleDownload}
468→            onEditModeChange={handleEditModeChange}
469→            onToggleAdjustMode={handleToggleAdjustMode}
470→            onViewChange={onViewChange}
471→            deletionsCount={deletion.deletionsCount}
472→            showDeleted={deletion.showDeleted}
473→            snapshotCount={snapshots.snapshots.length}
474→            onVersionsClick={() => setVersionsModalOpen(true)}
475→            onToggleShowDeleted={() =>
476→              deletion.setShowDeleted(!deletion.showDeleted)
477→            }
478→          />
479→
480→          {sessionError && !session.adjustModeEnabled ? (
481→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
482→              {sessionError}
483→            </div>
484→          ) : null}
485→
486→          {view === "reader" ? (
487→            <ErrorBoundary fallback={viewErrorFallback}>
488→              <div className="space-y-2">
489→                <div className="flex justify-end">
490→                  <SaveIndicator
491→                    isSaving={messageEdits.isSaving}
492→                    hasEdits={hasEdits}
493→                  />
494→                </div>
495→                <ReaderView
496→                  activeRules={rules.activeRules}
497→                  conversation={resolvedConversation}
498→                  adjustModeEnabled={session.adjustModeEnabled}
499→                  editMode={editMode === "edit"}
500→                  effectsMap={readerEffectsMap}
501→                  highlightedRuleId={rules.hoveredRuleId}
502→                  selectedBlock={
503→                    view === "reader" ? session.activeSelection : null
504→                  }
505→                  onSelectBlock={session.handleSelectionChange}
506→                  deletedMessageIds={deletion.deletedMessageIds}
507→                  showDeleted={deletion.showDeleted}
508→                  onBlocksChange={handleBlocksChange}
509→                  onCopyMessage={handleCopyMessage}
510→                  onDeleteMessage={handleDeleteMessage}
511→                  onDeleteRound={handleDeleteRound}
512→                  onRestoreMessage={deletion.restoreMessage}
513→                />
514→              </div>
515→            </ErrorBoundary>
516→          ) : view === "markdown" ? (
517→            <ErrorBoundary fallback={viewErrorFallback}>
518→              <MarkdownView
519→                activeRules={rules.activeRules}
520→                content={displayedMarkdown}
521→                adjustModeEnabled={session.adjustModeEnabled}
522→                highlightedRuleId={rules.hoveredRuleId}
523→                selectedRange={session.activeSelection}
524→                onSelectLines={session.handleSelectionChange}
525→              />
526→            </ErrorBoundary>
527→          ) : (
528→            <ErrorBoundary fallback={viewErrorFallback}>
529→              <ArtifactView content={artifact} />
530→            </ErrorBoundary>
531→          )}
532→
533→          {session.showGuide ? (
534→            <AdjustmentModeGuide
535→              view={view}
536→              onDismiss={() => session.setGuideDismissed(true)}
537→            />
538→          ) : null}
539→
540→          <ErrorBoundary
541→            fallback={
542→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
543→                {miscLabels.adjustmentLoadError}
544→              </div>
545→            }
546→          >
547→            <AdjustmentPopover
548→              anchor={session.activeAnchor ?? null}
549→              containerRef={session.sectionRef}
550→              draftMessage={session.activeDraftMessage}
551→              error={session.activeSessionError}
552→              isLoading={session.activeSessionLoading || session.isDiscarding}
553→              isSubmitting={session.isSubmitting}
554→              open={
555→                showPopover &&
556→                Boolean(session.activeSelection) &&
557→                Boolean(session.activeAnchor)
558→              }
559→              sessionDetail={session.activeSessionDetail}
560→              showReply={session.replyVisible}
561→              view={view}
562→              onClose={handlePopoverClose}
563→              onDraftMessageChange={session.handleDraftMessageChange}
564→              onRejectLastChange={handleRejectLastChange}
565→              onSubmitMessage={session.handleSubmitMessage}
566→            />
567→          </ErrorBoundary>
568→        </div>
569→      )}
570→
571→      {deleteDialog && (
572→        <DeleteMessageDialog
573→          messagePreview={deleteDialog.preview}
574→          isRound={deleteDialog.isRound}
575→          onConfirm={(reason) => {
576→            void handleConfirmDelete(reason);
577→          }}
578→          onCancel={() => setDeleteDialog(null)}
579→        />
580→      )}
581→
582→      {deletionToast.toast && (
583→        <UndoToast
584→          message={deletionToast.toast.message}
585→          onUndo={() => {
586→            void handleUndoDelete();
587→          }}
588→          onDismiss={deletionToast.dismissToast}
589→        />
590→      )}
591→
592→      <VersionsModal
593→        open={versionsModalOpen}
594→        onOpenChange={setVersionsModalOpen}
595→        snapshots={snapshots.snapshots}
596→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
597→        onActivate={(snapshotId) => {
598→          void snapshots.activate(snapshotId);
599→        }}
600→        onDeactivate={() => {
601→          void snapshots.deactivate();
602→        }}
603→        onCreate={(label) => {
604→          void snapshots.create(label);
605→        }}
606→        onRename={(snapshotId, label) => {
607→          void snapshots.rename(snapshotId, label);
608→        }}
609→        onDelete={(snapshotId) => {
610→          void snapshots.delete(snapshotId);
611→        }}
612→      />
613→    </section>
614→  );
615→}
