 26→export function resolveReaderBlockEffects(
 27→  rules: FormatRule[],
 28→  messageId: string,
 29→  blockIndex: number,
 30→  blockType: Block["type"],
 31→  blockText: string,
 32→  context?: ReaderMatchContext,
 33→) {
 34→  return rules
 35→    .filter(
 36→      (rule) =>
 37→        rule.status === "active" &&
 38→        matchesReaderRule(
 39→          rule,
 40→          messageId,
 41→          blockIndex,
 42→          blockType,
 43→          blockText,
 44→          context,
 45→        ),
 46→    )
 47→    .map((rule) => rule.compiledRule)
 48→    .filter((effect): effect is RuleEffect => effect !== undefined)
 49→    .map(normalizeLegacyEffect);
 50→}
 51→
 52→export function buildReaderEffectsMap(
 53→  rules: FormatRule[],
 54→  conversation: Conversation,
 55→): Map<string, RuleEffect[]> {
 56→  const activeRules = rules.filter((r) => r.status === "active");
 57→  const effectsMap = new Map<string, RuleEffect[]>();
 58→
 59→  for (const message of conversation.messages) {
 60→    const context: ReaderMatchContext = {
 61→      messageRole: message.role,
 62→      blocks: message.blocks,
 63→    };
 64→
 65→    for (
 66→      let blockIndex = 0;
 67→      blockIndex < message.blocks.length;
 68→      blockIndex += 1
 69→    ) {
 70→      const block = message.blocks[blockIndex];
 71→
 72→      if (!block) {
 73→        continue;
 74→      }
 75→
 76→      const effects = activeRules
 77→        .filter((rule) =>
 78→          matchesReaderRule(
 79→            rule,
 80→            message.id,
 81→            blockIndex,
 82→            block.type,
 83→            blockToPlainText(block),
 84→            context,
 85→          ),
 86→        )
 87→        .map((rule) => rule.compiledRule)
 88→        .filter((effect): effect is RuleEffect => effect !== undefined)
 89→        .map(normalizeLegacyEffect);
 90→
 91→      if (effects.length > 0) {
 92→        effectsMap.set(`${message.id}:${blockIndex}`, effects);
 93→      }
 94→    }
 95→  }
 96→
 97→  return effectsMap;
 98→}
