}
// Individual generators: markdownGenerator, handoverGenerator, jsonGenerator
```

### What to do:

1. **Change `importArtifactsSchema` in `packages/shared/src/imports.ts`** from fixed object shape to `z.record(z.string())` — this makes it a `Record<string, string>`. This is needed because the registry can produce dynamic keys.

2. **Change `buildArtifacts()` in `import-store.ts`** to use the ArtifactGeneratorRegistry:
```typescript
import { ArtifactGeneratorRegistry, markdownGenerator, handoverGenerator, jsonGenerator } from "./artifact-generators.js";

const generatorRegistry = new ArtifactGeneratorRegistry();
generatorRegistry.register(markdownGenerator);
generatorRegistry.register(handoverGenerator);
generatorRegistry.register(jsonGenerator);

function buildArtifacts(job: ImportJob): ImportArtifacts {
  const conversation = job.conversation;
  if (!conversation) {
    const artifacts: Record<string, string> = {};
    for (const gen of generatorRegistry.getAll()) {
      artifacts[gen.formatId] = "";
    }
    return artifacts;
  }
  const artifacts: Record<string, string> = {};
  for (const gen of generatorRegistry.getAll()) {
    artifacts[gen.formatId] = gen.generate(conversation);
  }
  return artifacts;
