import { BUILTIN_FORMATS } from "@chat-exporter/shared";
import { FormatPluginRegistry, clientFormatRegistry } from "./format-plugins";
import type { FormatPlugin } from "./format-plugins";

// ---------------------------------------------------------------------------
// FormatPluginRegistry — Unit Tests
// ---------------------------------------------------------------------------

describe("FormatPluginRegistry", () => {
  function createTestPlugin(
    overrides: Partial<FormatPlugin> = {},
  ): FormatPlugin {
    return {
      descriptor: {
        id: "test-format",
        label: "Test",
        adjustable: false,
        supportedRuleKinds: [],
        exportMimeType: "text/plain",
        exportExtension: ".txt",
      },
      ViewComponent: () => null,
      ...overrides,
    };
  }

  describe("register", () => {
    test("stores a plugin and makes it retrievable by id", () => {
      const registry = new FormatPluginRegistry();
      const plugin = createTestPlugin();

      registry.register(plugin);

      expect(registry.get("test-format")).toBe(plugin);
    });

    test("throws when registering a duplicate id", () => {
      const registry = new FormatPluginRegistry();
      registry.register(createTestPlugin());

      expect(() => registry.register(createTestPlugin())).toThrow(
        'Format plugin "test-format" is already registered.',
      );
    });
  });

  describe("get", () => {
    test("returns undefined for unknown id", () => {
      const registry = new FormatPluginRegistry();

      expect(registry.get("nonexistent")).toBeUndefined();
    });
  });

  describe("getAll", () => {
    test("returns all registered plugins", () => {
      const registry = new FormatPluginRegistry();
      const p1 = createTestPlugin({
        descriptor: { ...createTestPlugin().descriptor, id: "a" },
      });
      const p2 = createTestPlugin({
        descriptor: { ...createTestPlugin().descriptor, id: "b" },
      });

      registry.register(p1);
      registry.register(p2);

      expect(registry.getAll()).toEqual([p1, p2]);
    });

    test("returns empty array when no plugins registered", () => {
      const registry = new FormatPluginRegistry();

      expect(registry.getAll()).toEqual([]);
    });

    test("returns a copy — mutations do not affect registry", () => {
      const registry = new FormatPluginRegistry();
      registry.register(createTestPlugin());

      const all = registry.getAll();
      all.pop();

      expect(registry.getAll()).toHaveLength(1);
    });
  });
});

// ---------------------------------------------------------------------------
// clientFormatRegistry — Built-in Plugins
// ---------------------------------------------------------------------------

describe("clientFormatRegistry", () => {
  test("has all 4 built-in formats registered", () => {
    const all = clientFormatRegistry.getAll();

    expect(all).toHaveLength(4);

    const ids = all.map((p) => p.descriptor.id);
    expect(ids).toContain("reader");
    expect(ids).toContain("markdown");
    expect(ids).toContain("handover");
    expect(ids).toContain("json");
  });

  test("each plugin's descriptor matches the shared BUILTIN_FORMATS", () => {
    for (const builtinDescriptor of BUILTIN_FORMATS) {
      const plugin = clientFormatRegistry.get(builtinDescriptor.id);
      expect(plugin).toBeDefined();
      expect(plugin!.descriptor).toEqual(builtinDescriptor);
    }
  });

  test("markdown plugin has prepareDownload defined", () => {
    const plugin = clientFormatRegistry.get("markdown");

    expect(plugin?.prepareDownload).toBeTypeOf("function");
  });

  test("markdown plugin has prepareCopy defined", () => {
    const plugin = clientFormatRegistry.get("markdown");

    expect(plugin?.prepareCopy).toBeTypeOf("function");
  });

  test("reader plugin has no prepareDownload (complex deps handled elsewhere)", () => {
    const plugin = clientFormatRegistry.get("reader");

    expect(plugin?.prepareDownload).toBeUndefined();
  });

  test("handover and json plugins have no prepareDownload or prepareCopy", () => {
    for (const id of ["handover", "json"]) {
      const plugin = clientFormatRegistry.get(id);
      expect(plugin?.prepareDownload).toBeUndefined();
      expect(plugin?.prepareCopy).toBeUndefined();
    }
  });

  test("all plugins have a ViewComponent", () => {
    for (const plugin of clientFormatRegistry.getAll()) {
      expect(plugin.ViewComponent).toBeTypeOf("function");
    }
  });
});

import type { OutputFormatDescriptor } from "@chat-exporter/shared";
import { BUILTIN_FORMATS } from "@chat-exporter/shared";
import type { ComponentType } from "react";

import type { Conversation, FormatRule } from "@chat-exporter/shared";
import { ArtifactView } from "@/components/format-workspace/artifact-view";
import { applyMarkdownRules } from "@/components/format-workspace/rule-engine";

// ---------------------------------------------------------------------------
// Interfaces
// ---------------------------------------------------------------------------

export interface FormatViewProps {
  conversation: Conversation;
  rules: FormatRule[];
  importId: string;
}

export interface FormatPlugin {
  descriptor: OutputFormatDescriptor;
  /** View component for rendering this format. Props vary per format. */
  // biome-ignore lint/suspicious/noExplicitAny: View components have format-specific props; unified in Step 12
  ViewComponent: ComponentType<any>;
  /** Optional client-side transformation for download export. */
  prepareDownload?: (content: string, rules: FormatRule[]) => string;
  /** Optional client-side transformation for copy-to-clipboard. */
  prepareCopy?: (content: string, rules: FormatRule[]) => string;
}

// ---------------------------------------------------------------------------
// Registry
// ---------------------------------------------------------------------------

export class FormatPluginRegistry {
  private plugins = new Map<string, FormatPlugin>();

  register(plugin: FormatPlugin): void {
    if (this.plugins.has(plugin.descriptor.id)) {
      throw new Error(
        `Format plugin "${plugin.descriptor.id}" is already registered.`,
      );
    }
    this.plugins.set(plugin.descriptor.id, plugin);
  }

  get(id: string): FormatPlugin | undefined {
    return this.plugins.get(id);
  }

  getAll(): FormatPlugin[] {
    return [...this.plugins.values()];
  }
}

// ---------------------------------------------------------------------------
// Default client registry with built-in formats
// ---------------------------------------------------------------------------

export const clientFormatRegistry = new FormatPluginRegistry();

const [readerDesc, markdownDesc, handoverDesc, jsonDesc] = BUILTIN_FORMATS;

clientFormatRegistry.register({
  descriptor: readerDesc,
  ViewComponent: ArtifactView, // Placeholder — Step 12 wires up ReaderView
});

clientFormatRegistry.register({
  descriptor: markdownDesc,
  ViewComponent: ArtifactView, // Placeholder — Step 12 wires up MarkdownView
  prepareDownload: (content, rules) => applyMarkdownRules(content, rules),
  prepareCopy: (content, rules) => applyMarkdownRules(content, rules),
});

clientFormatRegistry.register({
  descriptor: handoverDesc,
  ViewComponent: ArtifactView,
});

clientFormatRegistry.register({
  descriptor: jsonDesc,
  ViewComponent: ArtifactView,
});

