 57→function isSupportedChatGptShareLink(urlString: string) {
 58→  let url: URL;
 59→  try {
 60→    url = new URL(urlString);
 61→  } catch {
 62→    return false;
 63→  }
 64→  return url.hostname === "chatgpt.com" && url.pathname.startsWith("/share/");
 65→}
