 67→const os = implement(contract);
 68→
 69→export const router = os.router({
 70→  imports: {
 71→    list: os.imports.list.handler(({ input }) => {
 72→      return listImportJobs(input);
 73→    }),
 74→
 75→    delete: os.imports.delete.handler(({ input }) => {
 76→      const job = getImportJob(input.id);
 77→      if (!job) {
 78→        throw new ORPCError("NOT_FOUND", {
 79→          message: "Import nicht gefunden.",
 80→        });
 81→      }
 82→      const deleted = deleteImportJob(input.id);
 83→      return { deleted };
 84→    }),
 85→
 86→    create: os.imports.create.handler(({ input }) => {
 87→      if (!isSupportedChatGptShareLink(input.url)) {
 88→        throw new ORPCError("BAD_REQUEST", {
 89→          message:
 90→            "Dieser erste Stand akzeptiert nur öffentliche ChatGPT-Share-Links.",
 91→        });
 92→      }
 93→
 94→      const job = createImportJob(input);
 95→      void runImportJob(job.id);
 96→      return job;
 97→    }),
 98→
 99→    get: os.imports.get.handler(({ input }) => {
100→      const job = getImportJob(input.id);
101→
102→      if (!job) {
103→        throw new ORPCError("NOT_FOUND", {
104→          message: "Import nicht gefunden.",
105→        });
106→      }
107→
108→      return job;
109→    }),
110→
111→    snapshot: os.imports.snapshot.handler(({ input }) => {
112→      const snapshot = getPersistedImportSnapshot(input.id);
113→
114→      if (!snapshot) {
115→        throw new ORPCError("NOT_FOUND", {
116→          message: "Import-Snapshot nicht gefunden.",
117→        });
118→      }
119→
120→      const rawHtmlPreview = snapshot.rawHtml.slice(0, RAW_HTML_PREVIEW_LENGTH);
121→
122→      return importSnapshotSchema.parse({
123→        importId: snapshot.importId,
124→        sourceUrl: snapshot.sourceUrl,
125→        finalUrl: snapshot.finalUrl,
126→        fetchedAt: snapshot.fetchedAt,
127→        pageTitle: snapshot.pageTitle,
128→        rawHtmlBytes: Buffer.byteLength(snapshot.rawHtml, "utf8"),
129→        rawHtmlPreview,
130→        rawHtmlTruncated: snapshot.rawHtml.length > rawHtmlPreview.length,
131→        normalizedPayload: snapshot.normalizedPayload,
132→        fetchMetadata: snapshot.fetchMetadata,
133→      });
134→    }),
135→
136→    rawHtml: os.imports.rawHtml.handler(({ input }) => {
137→      const snapshot = getPersistedImportSnapshot(input.id);
138→
139→      if (!snapshot) {
140→        throw new ORPCError("NOT_FOUND", {
141→          message: "Import-Snapshot nicht gefunden.",
142→        });
143→      }
144→
145→      return snapshot.rawHtml;
146→    }),
147→
148→    // Design-Entscheidung: Dieser Endpoint liefert absichtlich rohe, unveränderte
149→    // Artefakte ohne angewendete Format-Rules. Client-seitiger Markdown-Download
150→    // verwendet stattdessen `displayedMarkdown` (mit `applyMarkdownRules` inkl.
151→    // format_profile-Rules). Änderungen hier dürfen diese Trennung nicht aufheben.
152→    exportArtifact: os.imports.exportArtifact.handler(({ input }) => {
153→      const job = getImportJob(input.id);
154→
155→      const artifact = job?.artifacts?.[input.format];
156→
157→      if (!artifact) {
158→        throw new ORPCError("NOT_FOUND", {
159→          message: "Export-Artefakt nicht gefunden.",
160→        });
161→      }
162→
163→      return artifact;
164→    }),
165→  },
166→
167→  adjustments: {
168→    listSessions: os.adjustments.listSessions.handler(({ input }) => {
169→      const job = getImportJob(input.importId);
170→
171→      if (!job) {
172→        throw new ORPCError("NOT_FOUND", {
173→          message: "Import nicht gefunden.",
174→        });
175→      }
176→
177→      return listAdjustmentSessions(input.importId, input.format);
178→    }),
179→
180→    createSession: os.adjustments.createSession.handler(({ input }) => {
181→      const job = getImportJob(input.importId);
182→
183→      if (!job) {
184→        throw new ORPCError("NOT_FOUND", {
185→          message: "Import nicht gefunden.",
186→        });
187→      }
188→
189→      const { session } = createAdjustmentSession({
190→        importId: input.importId,
191→        selection: input.selection,
192→        targetFormat: input.targetFormat,
193→      });
194→      const detail = getAdjustmentSessionDetail(session.id);
195→
196→      if (!detail) {
197→        throw new ORPCError("INTERNAL_SERVER_ERROR", {
198→          message: "Anpassungssession konnte nicht geladen werden.",
199→        });
200→      }
201→
202→      return detail;
203→    }),
204→
205→    getSession: os.adjustments.getSession.handler(({ input }) => {
206→      const detail = getAdjustmentSessionDetail(input.id);
207→
208→      if (!detail) {
209→        throw new ORPCError("NOT_FOUND", {
210→          message: "Anpassungssession nicht gefunden.",
211→        });
212→      }
213→
214→      return detail;
215→    }),
216→
217→    appendMessage: os.adjustments.appendMessage.handler(async ({ input }) => {
218→      const detail = getAdjustmentSessionDetail(input.sessionId);
219→
220→      if (!detail) {
221→        throw new ORPCError("NOT_FOUND", {
222→          message: "Anpassungssession nicht gefunden.",
223→        });
224→      }
225→
226→      // Phase 1 — Transaction: reopen (if needed) + append user message + reload detail
227→      const latestDetail = withTransaction(() => {
228→        const freshDetail = getAdjustmentSessionDetail(input.sessionId);
229→
230→        if (!freshDetail) {
231→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
232→            message: "Anpassungssession konnte nicht neu geladen werden.",
233→          });
234→        }
235→
236→        if (freshDetail.session.status === "applied") {
237→          reopenAdjustmentSession(input.sessionId);
238→        }
239→
240→        appendAdjustmentMessage(input.sessionId, "user", input.content);
241→
242→        const reloaded = getAdjustmentSessionDetail(input.sessionId);
243→
244→        if (!reloaded) {
245→          throw new ORPCError("INTERNAL_SERVER_ERROR", {
246→            message: "Anpassungssession konnte nicht neu geladen werden.",
247→          });
248→        }
249→
250→        return reloaded;
251→      });
252→
253→      const activeRules = listFormatRules(
254→        detail.session.importId,
255→        detail.session.targetFormat,
256→      ).filter((rule: { status: string }) => rule.status === "active");
257→
258→      // Phase 2 — no wrapper: async AI call
259→      try {
260→        const job = getImportJob(detail.session.importId);
261→        const result = await runAgentTurn({
262→          sessionDetail: latestDetail,
263→          activeRules,
264→          job,
265→          callbacks: {
266→            onCreateRule: async ({ selector, effect, description }) => {
267→              const rule = createFormatRuleDirect({
268→                importId: latestDetail.session.importId,
269→                targetFormat: latestDetail.session.targetFormat,
270→                selector,
271→                effect: {
272→                  type: "custom_style" as const,
273→                  ...effect,
274→                  description,
275→                },
276→                instruction: description,
277→                sourceSessionId: input.sessionId,
278→              });
279→              return { ruleId: rule.id };
280→            },
281→            onUpdateRule: async ({ ruleId, effect, description }) => {
282→              updateFormatRuleEffect(
283→                ruleId,
284→                { type: "custom_style" as const, ...effect, description },
285→                description,
286→              );
287→            },
288→            onDeleteRule: async (ruleId) => {
289→              disableFormatRule(ruleId, latestDetail.session.importId);
290→            },
291→          },
292→        });
293→
294→        // Phase 3 — persist assistant message + events
295→        withTransaction(() => {
296→          appendAdjustmentMessage(
297→            input.sessionId,
298→            "assistant",
299→            result.assistantMessage,
300→          );
301→
302→          for (const action of result.actions) {
303→            recordAdjustmentEvent({
304→              importId: latestDetail.session.importId,
305→              ruleId: action.ruleId,
306→              sessionId: input.sessionId,
307→              targetFormat: latestDetail.session.targetFormat,
308→              type:
309→                action.type === "deleted" ? "rule_disabled" : "rule_applied",
310→            });
311→          }
312→
313→          if (result.actions.length > 0) {
314→            markSessionApplied(input.sessionId);
315→          } else {
316→            recordAdjustmentEvent({
317→              importId: latestDetail.session.importId,
318→              sessionId: input.sessionId,
319→              targetFormat: latestDetail.session.targetFormat,
320→              type: "clarification_requested",
321→            });
322→          }
323→        });
324→      } catch (error) {
325→        if (error instanceof AgentUnavailableError) {
326→          throw new ORPCError("SERVICE_UNAVAILABLE", {
327→            message: error.message,
328→          });
329→        }
330→        if (error instanceof DOMException && error.name === "TimeoutError") {
331→          throw new ORPCError("GATEWAY_TIMEOUT", {
332→            message: "Die KI hat zu lange gebraucht. Bitte versuche es erneut.",
333→          });
334→        }
335→        throw new ORPCError("BAD_REQUEST", {
336→          message:
