  6→import { AdjustmentPopover } from "@/components/format-workspace/adjustment-popover";
  7→import { ArtifactView } from "@/components/format-workspace/artifact-view";
  8→import { CompletedToolbar } from "@/components/format-workspace/completed-toolbar";
  9→import { DeleteMessageDialog } from "@/components/format-workspace/delete-message-dialog";
 10→import {
 11→  formatMarkdownLinesLabel,
 12→  formatMessageBlockLabel,
 13→  getImportStageLabel,
 14→  miscLabels,
 15→} from "@/components/format-workspace/labels";
 16→import { LoadingStateBlock } from "@/components/format-workspace/loading-state-block";
 17→import { MarkdownView } from "@/components/format-workspace/markdown-view";
 18→import { copyMessageToClipboard } from "@/components/format-workspace/message-clipboard";
 19→import { buildReaderHtml } from "@/components/format-workspace/reader-html-export";
 20→import { ReaderView } from "@/components/format-workspace/reader-view";
 21→import {
 22→  applyMarkdownRules,
 23→  buildReaderEffectsMap,
 24→} from "@/components/format-workspace/rule-engine";
 25→import { SaveIndicator } from "@/components/format-workspace/save-indicator";
 26→import { StatusHeader } from "@/components/format-workspace/status-header";
 27→import {
 28→  type AdjustmentSelection,
 29→  adjustableViews,
 30→  type EditMode,
 31→  type ViewMode,
 32→} from "@/components/format-workspace/types";
 33→import { UndoToast } from "@/components/format-workspace/undo-toast";
 34→import { useAdjustmentPopover } from "@/components/format-workspace/use-adjustment-popover";
 35→import { useAdjustmentSession } from "@/components/format-workspace/use-adjustment-session";
 36→import { useAutoSnapshot } from "@/components/format-workspace/use-auto-snapshot";
 37→import { useDeletionToast } from "@/components/format-workspace/use-deletion-toast";
 38→import { useFormatRules } from "@/components/format-workspace/use-format-rules";
 39→import { useMessageDeletion } from "@/components/format-workspace/use-message-deletion";
 40→import { useMessageEdits } from "@/components/format-workspace/use-message-edits";
 41→import { useResolvedConversation } from "@/components/format-workspace/use-resolved-conversation";
 42→import { useSnapshots } from "@/components/format-workspace/use-snapshots";
 43→import { VersionsModal } from "@/components/format-workspace/versions-modal";
 44→
 45→type ActiveStage = {
 46→  detail: string;
 47→  label: string;
 48→} | null;
 49→
 50→type FormatWorkspaceProps = {
 51→  activeStage: ActiveStage;
 52→  elapsedTime: string;
 53→  job: ImportJob;
 54→  view: ViewMode;
 55→  onViewChange: (view: ViewMode) => void;
 56→};
 57→
 58→function _describeSelectionLabel(selection: AdjustmentSelection) {
 59→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 60→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 61→  }
 62→
 63→  return formatMessageBlockLabel(
 64→    selection.messageRole,
 65→    selection.messageIndex + 1,
 66→    selection.blockType,
 67→  );
 68→}
 69→
 70→export function FormatWorkspace({
 71→  activeStage,
 72→  elapsedTime,
 73→  job,
 74→  view,
 75→  onViewChange,
 76→}: FormatWorkspaceProps) {
 77→  const isAdjustableView = adjustableViews.has(view);
 78→
 79→  const session = useAdjustmentSession(view, job.id);
 80→  const rules = useFormatRules(view, job.id);
 81→  const snapshots = useSnapshots(job.id);
 82→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 83→  const resolvedMessages = useResolvedConversation(
 84→    job.conversation,
 85→    messageEdits.editedMessagesMap,
 86→  );
 87→  const autoSnapshot = useAutoSnapshot({
 88→    activeSnapshot: snapshots.activeSnapshot,
 89→    create: snapshots.create,
 90→    activate: snapshots.activate,
 91→  });
 92→  const deletion = useMessageDeletion(job.id);
 93→  const deletionToast = useDeletionToast();
 94→  const [editMode, setEditMode] = useState<EditMode>("view");
 95→
 96→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
 97→  const handleEditModeChange = useCallback(
 98→    (mode: EditMode) => {
 99→      if (mode === "edit" && session.adjustModeEnabled) {
100→        session.toggleAdjustMode();
101→      }
102→      setEditMode(mode);
103→    },
104→    [session],
105→  );
106→
107→  const handleToggleAdjustMode = useCallback(() => {
108→    if (!session.adjustModeEnabled && editMode === "edit") {
109→      setEditMode("view");
110→    }
111→    session.toggleAdjustMode();
112→  }, [session, editMode]);
113→
114→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
115→
116→  // beforeunload warning when unsaved edits exist.
117→  // hasPendingEdits covers both debounce timers that haven't fired yet and
118→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
119→  // window where isSaving alone would still be false.
120→  useEffect(() => {
121→    if (!messageEdits.hasPendingEdits) return;
122→    const handler = (e: BeforeUnloadEvent) => {
123→      e.preventDefault();
124→    };
125→    window.addEventListener("beforeunload", handler);
126→    return () => window.removeEventListener("beforeunload", handler);
127→  }, [messageEdits.hasPendingEdits]);
128→
129→  const handleBlocksChange = useCallback(
130→    (messageId: string, blocks: Block[]) => {
131→      void autoSnapshot.ensureSnapshot().then((ready) => {
132→        if (ready) {
133→          messageEdits.saveEdit(messageId, blocks);
134→        }
135→      });
136→    },
137→    [autoSnapshot, messageEdits],
138→  );
139→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
140→  const [deleteDialog, setDeleteDialog] = useState<{
141→    messageId: string;
142→    isRound: boolean;
143→    preview: string;
144→  } | null>(null);
145→  const popover = useAdjustmentPopover();
146→
147→  const handleDeleteMessage = useCallback(
148→    (messageId: string) => {
149→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
150→      const preview =
151→        msg?.blocks
152→          .map((b) => ("text" in b ? b.text : b.type))
153→          .join(" ")
154→          .slice(0, 200) ?? messageId;
155→      setDeleteDialog({ messageId, isRound: false, preview });
156→    },
157→    [job.conversation?.messages],
158→  );
159→
160→  const handleDeleteRound = useCallback(
161→    (messageId: string) => {
162→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
163→      const preview =
164→        msg?.blocks
165→          .map((b) => ("text" in b ? b.text : b.type))
166→          .join(" ")
167→          .slice(0, 200) ?? messageId;
168→      setDeleteDialog({ messageId, isRound: true, preview });
169→    },
170→    [job.conversation?.messages],
171→  );
172→
173→  const handleConfirmDelete = useCallback(
174→    async (reason?: string) => {
175→      if (!deleteDialog) return;
176→      const { messageId, isRound } = deleteDialog;
177→      setDeleteDialog(null);
178→      if (isRound) {
179→        const result = await deletion.deleteRound(messageId, reason);
180→        deletionToast.showDeletedToast(messageId, true, result.length);
181→      } else {
182→        await deletion.deleteMessage(messageId, reason);
183→        deletionToast.showDeletedToast(messageId, false);
184→      }
185→    },
186→    [deleteDialog, deletion, deletionToast],
187→  );
188→
189→  const handleUndoDelete = useCallback(async () => {
190→    if (!deletionToast.toast) return;
191→    await deletion.restoreMessage(deletionToast.toast.messageId);
192→    deletionToast.dismissToast();
193→  }, [deletion, deletionToast]);
194→
195→  const mergedRef = useCallback(
196→    (node: HTMLElement | null) => {
197→      (
198→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
199→      ).current = node;
200→      (
201→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
202→      ).current = node;
203→    },
204→    [session.sectionRef, popover.containerRef],
205→  );
206→
207→  const artifact =
208→    view === "reader"
209→      ? ""
210→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
211→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
212→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
213→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
214→  const displayedMarkdown = useMemo(() => {
215→    if (view !== "markdown") return artifact;
216→    try {
217→      return applyMarkdownRules(artifact, rules.activeRules);
218→    } catch {
219→      return artifact;
220→    }
221→  }, [artifact, rules.activeRules, view]);
222→
223→  const resolvedConversation = useMemo(() => {
224→    if (!job.conversation) return undefined;
225→    return {
226→      ...job.conversation,
227→      messages: resolvedMessages.map((rm) => ({
228→        id: rm.id,
229→        role: rm.role,
230→        blocks: rm.blocks,
231→      })),
232→    };
233→  }, [job.conversation, resolvedMessages]);
234→
235→  const readerEffectsMap = useMemo(
236→    () =>
237→      view === "reader" && resolvedConversation
238→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
239→        : new Map(),
240→    [rules.activeRules, resolvedConversation, view],
241→  );
242→
243→  const handleCopyMessage = useCallback(
244→    (messageId: string) => {
245→      const msg = resolvedConversation?.messages.find(
246→        (m) => m.id === messageId,
247→      );
248→      if (!msg) return;
249→      void copyMessageToClipboard(msg, view, msg.blocks);
250→    },
251→    [resolvedConversation, view],
252→  );
253→
254→  const [copySuccess, setCopySuccess] = useState(false);
255→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
256→
257→  const handleCopyAll = useMemo(() => {
258→    const doCopy = async (content: string, isHtml: boolean) => {
259→      try {
260→        if (isHtml) {
261→          const blob = new Blob([content], { type: "text/html" });
262→          const plainBlob = new Blob([content], { type: "text/plain" });
263→          await navigator.clipboard.write([
264→            new ClipboardItem({
265→              "text/html": blob,
266→              "text/plain": plainBlob,
267→            }),
268→          ]);
269→        } else {
270→          await navigator.clipboard.writeText(content);
271→        }
272→        clearTimeout(copyTimeoutRef.current);
273→        setCopySuccess(true);
274→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
275→      } catch {
276→        // Fallback: silently fail
277→      }
278→    };
279→
280→    if (view === "markdown") {
281→      return () => {
282→        void doCopy(displayedMarkdown, false);
283→      };
284→    }
285→    if (view === "reader" && resolvedConversation) {
286→      return () => {
287→        const html = buildReaderHtml(
288→          resolvedConversation,
289→          readerEffectsMap,
290→          resolvedConversation.title ?? `export-${job.id}`,
291→        );
292→        void doCopy(html, true);
293→      };
294→    }
295→    if ((view === "handover" || view === "json") && artifact) {
296→      return () => {
297→        void doCopy(artifact, false);
298→      };
299→    }
300→    return undefined;
301→  }, [
302→    view,
303→    displayedMarkdown,
304→    job.id,
305→    resolvedConversation,
306→    readerEffectsMap,
307→    artifact,
308→  ]);
309→
310→  const handleDownload = useMemo(() => {
311→    if (view === "markdown") {
312→      return () => {
313→        const blob = new Blob([displayedMarkdown], { type: "text/markdown" });
314→        const url = URL.createObjectURL(blob);
315→        const a = document.createElement("a");
316→        a.href = url;
317→        a.download = `export-${job.id}.md`;
318→        document.body.appendChild(a);
319→        a.click();
320→        document.body.removeChild(a);
321→        setTimeout(() => URL.revokeObjectURL(url), 100);
322→      };
323→    }
324→    if (view === "reader" && resolvedConversation) {
325→      return () => {
326→        const html = buildReaderHtml(
327→          resolvedConversation,
328→          readerEffectsMap,
329→          resolvedConversation.title ?? `export-${job.id}`,
330→        );
331→        const blob = new Blob([html], { type: "text/html" });
332→        const url = URL.createObjectURL(blob);
333→        const a = document.createElement("a");
334→        a.href = url;
335→        a.download = `export-${job.id}.html`;
336→        document.body.appendChild(a);
337→        a.click();
338→        document.body.removeChild(a);
339→        setTimeout(() => URL.revokeObjectURL(url), 100);
340→      };
341→    }
342→    if ((view === "handover" || view === "json") && artifact) {
343→      return () => {
344→        const ext = view === "json" ? "json" : "md";
345→        const blob = new Blob([artifact], { type: "text/plain" });
346→        const url = URL.createObjectURL(blob);
347→        const a = document.createElement("a");
348→        a.href = url;
349→        a.download = `export-${job.id}.${ext}`;
350→        document.body.appendChild(a);
351→        a.click();
352→        document.body.removeChild(a);
353→        setTimeout(() => URL.revokeObjectURL(url), 100);
354→      };
355→    }
356→    return undefined;
357→  }, [
358→    view,
359→    displayedMarkdown,
360→    job.id,
361→    resolvedConversation,
362→    readerEffectsMap,
363→    artifact,
364→  ]);
365→  const showPopover =
366→    session.adjustModeEnabled &&
367→    Boolean(session.activeSelection) &&
368→    Boolean(session.activeAnchor);
369→
370→  const popoverCallbacksRef = useRef({
371→    handleDiscardSession: session.handleDiscardSession,
372→    activeSessionDetail: session.activeSessionDetail,
373→    handleRejectLastChange: rules.handleRejectLastChange,
374→    setReplyVisible: session.setReplyVisible,
375→  });
376→  popoverCallbacksRef.current = {
377→    handleDiscardSession: session.handleDiscardSession,
378→    activeSessionDetail: session.activeSessionDetail,
379→    handleRejectLastChange: rules.handleRejectLastChange,
380→    setReplyVisible: session.setReplyVisible,
381→  };
382→
383→  const handlePopoverClose = useCallback(() => {
384→    popoverCallbacksRef.current.handleDiscardSession();
385→  }, []);
386→
387→  const handleRejectLastChange = useCallback(() => {
388→    const {
389→      activeSessionDetail,
390→      handleRejectLastChange: reject,
391→      setReplyVisible,
392→    } = popoverCallbacksRef.current;
393→    if (activeSessionDetail) {
394→      void reject(activeSessionDetail).then((success) => {
395→        if (success) setReplyVisible(false);
396→      });
397→    }
398→  }, []);
399→
400→  const sessionError =
401→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
402→
403→  const viewErrorFallback = (_error: Error, reset: () => void) => (
404→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
405→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
406→      <button
407→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
408→        type="button"
409→        onClick={reset}
410→      >
411→        {miscLabels.retryButton}
412→      </button>
413→    </div>
414→  );
415→
416→  return (
417→    <section
418→      ref={mergedRef}
419→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
420→    >
421→      <StatusHeader
422→        activeStage={activeStage}
423→        elapsedTime={elapsedTime}
424→        job={job}
425→      />
426→
427→      {job.warnings.length > 0 ? (
428→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
429→          {job.warnings[0]}
430→        </div>
431→      ) : null}
432→
433→      {job.status === "failed" ? (
434→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
435→          <p className="font-medium">{miscLabels.importFailed}</p>
436→          {job.errorStage && job.errorStage !== "done" && (
437→            <p className="text-sm mt-1">
438→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
439→            </p>
440→          )}
441→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
442→        </div>
443→      ) : job.status === "queued" || job.status === "running" ? (
444→        <LoadingStateBlock stageDetail={activeStage?.detail} />
445→      ) : (
446→        <div className="space-y-4">
447→          <CompletedToolbar
448→            adjustModeEnabled={session.adjustModeEnabled}
449→            copySuccess={copySuccess}
450→            editMode={editMode}
451→            isAdjustableView={isAdjustableView}
452→            rules={rules}
453→            view={view}
454→            onCopyAll={handleCopyAll}
455→            onDownloadMarkdown={handleDownload}
456→            onEditModeChange={handleEditModeChange}
457→            onToggleAdjustMode={handleToggleAdjustMode}
458→            onViewChange={onViewChange}
459→            deletionsCount={deletion.deletionsCount}
460→            showDeleted={deletion.showDeleted}
461→            snapshotCount={snapshots.snapshots.length}
462→            onVersionsClick={() => setVersionsModalOpen(true)}
463→            onToggleShowDeleted={() =>
464→              deletion.setShowDeleted(!deletion.showDeleted)
465→            }
466→          />
467→
468→          {sessionError && !session.adjustModeEnabled ? (
469→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
470→              {sessionError}
471→            </div>
472→          ) : null}
473→
474→          {view === "reader" ? (
475→            <ErrorBoundary fallback={viewErrorFallback}>
476→              <div className="space-y-2">
477→                <div className="flex justify-end">
478→                  <SaveIndicator
479→                    isSaving={messageEdits.isSaving}
480→                    hasEdits={hasEdits}
481→                  />
482→                </div>
483→                <ReaderView
484→                  activeRules={rules.activeRules}
485→                  conversation={resolvedConversation}
486→                  adjustModeEnabled={session.adjustModeEnabled}
487→                  editMode={editMode === "edit"}
488→                  effectsMap={readerEffectsMap}
489→                  highlightedRuleId={rules.hoveredRuleId}
490→                  selectedBlock={
491→                    view === "reader" ? session.activeSelection : null
492→                  }
493→                  onSelectBlock={session.handleSelectionChange}
494→                  deletedMessageIds={deletion.deletedMessageIds}
495→                  showDeleted={deletion.showDeleted}
496→                  onBlocksChange={handleBlocksChange}
497→                  onCopyMessage={handleCopyMessage}
498→                  onDeleteMessage={handleDeleteMessage}
499→                  onDeleteRound={handleDeleteRound}
500→                  onRestoreMessage={deletion.restoreMessage}
501→                />
502→              </div>
503→            </ErrorBoundary>
504→          ) : view === "markdown" ? (
505→            <ErrorBoundary fallback={viewErrorFallback}>
506→              <MarkdownView
507→                activeRules={rules.activeRules}
508→                content={displayedMarkdown}
509→                adjustModeEnabled={session.adjustModeEnabled}
510→                highlightedRuleId={rules.hoveredRuleId}
511→                selectedRange={session.activeSelection}
512→                onSelectLines={session.handleSelectionChange}
513→              />
514→            </ErrorBoundary>
515→          ) : (
516→            <ErrorBoundary fallback={viewErrorFallback}>
517→              <ArtifactView content={artifact} />
518→            </ErrorBoundary>
519→          )}
520→
521→          {session.showGuide ? (
522→            <AdjustmentModeGuide
523→              view={view}
524→              onDismiss={() => session.setGuideDismissed(true)}
525→            />
526→          ) : null}
527→
528→          <ErrorBoundary
529→            fallback={
530→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
531→                {miscLabels.adjustmentLoadError}
532→              </div>
533→            }
534→          >
535→            <AdjustmentPopover
536→              anchor={session.activeAnchor ?? null}
537→              containerRef={session.sectionRef}
538→              draftMessage={session.activeDraftMessage}
539→              error={session.activeSessionError}
540→              isLoading={session.activeSessionLoading || session.isDiscarding}
541→              isSubmitting={session.isSubmitting}
542→              open={
543→                showPopover &&
544→                Boolean(session.activeSelection) &&
545→                Boolean(session.activeAnchor)
546→              }
547→              sessionDetail={session.activeSessionDetail}
548→              showReply={session.replyVisible}
549→              view={view}
550→              onClose={handlePopoverClose}
551→              onDraftMessageChange={session.handleDraftMessageChange}
552→              onRejectLastChange={handleRejectLastChange}
553→              onSubmitMessage={session.handleSubmitMessage}
554→            />
555→          </ErrorBoundary>
556→        </div>
557→      )}
558→
559→      {deleteDialog && (
560→        <DeleteMessageDialog
561→          messagePreview={deleteDialog.preview}
562→          isRound={deleteDialog.isRound}
563→          onConfirm={(reason) => {
564→            void handleConfirmDelete(reason);
565→          }}
566→          onCancel={() => setDeleteDialog(null)}
567→        />
568→      )}
569→
570→      {deletionToast.toast && (
571→        <UndoToast
572→          message={deletionToast.toast.message}
573→          onUndo={() => {
574→            void handleUndoDelete();
575→          }}
576→          onDismiss={deletionToast.dismissToast}
577→        />
578→      )}
579→
580→      <VersionsModal
581→        open={versionsModalOpen}
582→        onOpenChange={setVersionsModalOpen}
583→        snapshots={snapshots.snapshots}
584→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
585→        onActivate={(snapshotId) => {
586→          void snapshots.activate(snapshotId);
587→        }}
588→        onDeactivate={() => {
589→          void snapshots.deactivate();
590→        }}
591→        onCreate={(label) => {
592→          void snapshots.create(label);
593→        }}
594→        onRename={(snapshotId, label) => {
595→          void snapshots.rename(snapshotId, label);
596→        }}
597→        onDelete={(snapshotId) => {
598→          void snapshots.delete(snapshotId);
599→        }}
600→      />
601→    </section>
602→  );
603→}
