21→export interface FormatPlugin {
22→  descriptor: OutputFormatDescriptor;
23→  /** View component for rendering this format. Props vary per format. */
24→  // biome-ignore lint/suspicious/noExplicitAny: View components have format-specific props; unified in Step 12
25→  ViewComponent: ComponentType<any>;
26→  /** Optional client-side transformation for download export. */
27→  prepareDownload?: (content: string, rules: FormatRule[]) => string;
28→  /** Optional client-side transformation for copy-to-clipboard. */
29→  prepareCopy?: (content: string, rules: FormatRule[]) => string;
30→}
