32→// ---------------------------------------------------------------------------
33→// Registry
34→// ---------------------------------------------------------------------------
35→
36→export class FormatPluginRegistry {
37→  private plugins = new Map<string, FormatPlugin>();
38→
39→  register(plugin: FormatPlugin): void {
40→    if (this.plugins.has(plugin.descriptor.id)) {
41→      throw new Error(
42→        `Format plugin "${plugin.descriptor.id}" is already registered.`,
43→      );
44→    }
45→    this.plugins.set(plugin.descriptor.id, plugin);
46→  }
47→
48→  get(id: string): FormatPlugin | undefined {
49→    return this.plugins.get(id);
50→  }
51→
52→  getAll(): FormatPlugin[] {
53→    return [...this.plugins.values()];
54→  }
55→}
