57→// ---------------------------------------------------------------------------
58→// Default client registry with built-in formats
59→// ---------------------------------------------------------------------------
60→
61→export const clientFormatRegistry = new FormatPluginRegistry();
62→
63→for (const desc of BUILTIN_FORMATS) {
64→  switch (desc.id) {
65→    case "reader":
66→      clientFormatRegistry.register({
67→        descriptor: desc,
68→        ViewComponent: ArtifactView, // Placeholder — Step 12 wires up ReaderView
69→      });
70→      break;
71→    case "markdown":
72→      clientFormatRegistry.register({
73→        descriptor: desc,
74→        ViewComponent: ArtifactView, // Placeholder — Step 12 wires up MarkdownView
75→        prepareDownload: (content, rules) => applyMarkdownRules(content, rules),
76→        prepareCopy: (content, rules) => applyMarkdownRules(content, rules),
77→      });
78→      break;
79→    case "handover":
80→      clientFormatRegistry.register({
81→        descriptor: desc,
82→        ViewComponent: ArtifactView,
83→      });
84→      break;
85→    case "json":
86→      clientFormatRegistry.register({
87→        descriptor: desc,
88→        ViewComponent: ArtifactView,
89→      });
90→      break;
91→  }
92→}
