 58→function _describeSelectionLabel(selection: AdjustmentSelection) {
 59→  if (selection.lineStart !== undefined && selection.lineEnd !== undefined) {
 60→    return formatMarkdownLinesLabel(selection.lineStart, selection.lineEnd);
 61→  }
 62→
 63→  return formatMessageBlockLabel(
 64→    selection.messageRole,
 65→    selection.messageIndex + 1,
 66→    selection.blockType,
 67→  );
 68→}
 69→
 70→function downloadBlob(content: string, mimeType: string, filename: string) {
 71→  const blob = new Blob([content], { type: mimeType });
 72→  const url = URL.createObjectURL(blob);
 73→  const a = document.createElement("a");
 74→  a.href = url;
 75→  a.download = filename;
 76→  document.body.appendChild(a);
 77→  a.click();
 78→  document.body.removeChild(a);
 79→  setTimeout(() => URL.revokeObjectURL(url), 100);
 80→}
