 82→export function FormatWorkspace({
 83→  activeStage,
 84→  elapsedTime,
 85→  job,
 86→  view,
 87→  onViewChange,
 88→}: FormatWorkspaceProps) {
 89→  const isAdjustableView = adjustableViews.has(view);
 90→
 91→  const session = useAdjustmentSession(view, job.id);
 92→  const rules = useFormatRules(view, job.id);
 93→  const snapshots = useSnapshots(job.id);
 94→  const messageEdits = useMessageEdits(job.id, snapshots.activeSnapshot?.id);
 95→  const resolvedMessages = useResolvedConversation(
 96→    job.conversation,
 97→    messageEdits.editedMessagesMap,
 98→  );
 99→  const autoSnapshot = useAutoSnapshot({
100→    activeSnapshot: snapshots.activeSnapshot,
101→    create: snapshots.create,
102→    activate: snapshots.activate,
103→  });
104→  const deletion = useMessageDeletion(job.id);
105→  const deletionToast = useDeletionToast();
106→  const [editMode, setEditMode] = useState<EditMode>("view");
107→
108→  // Mutual exclusion: edit mode and adjustment mode must never be active simultaneously
109→  const handleEditModeChange = useCallback(
110→    (mode: EditMode) => {
111→      if (mode === "edit" && session.adjustModeEnabled) {
112→        session.toggleAdjustMode();
113→      }
114→      setEditMode(mode);
115→    },
116→    [session],
117→  );
118→
119→  const handleToggleAdjustMode = useCallback(() => {
120→    if (!session.adjustModeEnabled && editMode === "edit") {
121→      setEditMode("view");
122→    }
123→    session.toggleAdjustMode();
124→  }, [session, editMode]);
125→
126→  const hasEdits = resolvedMessages.some((m) => m.isEdited);
127→
128→  // beforeunload warning when unsaved edits exist.
129→  // hasPendingEdits covers both debounce timers that haven't fired yet and
130→  // in-flight HTTP mutations, preventing data loss during the 500 ms debounce
131→  // window where isSaving alone would still be false.
132→  useEffect(() => {
133→    if (!messageEdits.hasPendingEdits) return;
134→    const handler = (e: BeforeUnloadEvent) => {
135→      e.preventDefault();
136→    };
137→    window.addEventListener("beforeunload", handler);
138→    return () => window.removeEventListener("beforeunload", handler);
139→  }, [messageEdits.hasPendingEdits]);
140→
141→  const handleBlocksChange = useCallback(
142→    (messageId: string, blocks: Block[]) => {
143→      void autoSnapshot.ensureSnapshot().then((ready) => {
144→        if (ready) {
145→          messageEdits.saveEdit(messageId, blocks);
146→        }
147→      });
148→    },
149→    [autoSnapshot, messageEdits],
150→  );
151→  const [versionsModalOpen, setVersionsModalOpen] = useState(false);
152→  const [deleteDialog, setDeleteDialog] = useState<{
153→    messageId: string;
154→    isRound: boolean;
155→    preview: string;
156→  } | null>(null);
157→  const popover = useAdjustmentPopover();
158→
159→  const handleDeleteMessage = useCallback(
160→    (messageId: string) => {
161→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
162→      const preview =
163→        msg?.blocks
164→          .map((b) => ("text" in b ? b.text : b.type))
165→          .join(" ")
166→          .slice(0, 200) ?? messageId;
167→      setDeleteDialog({ messageId, isRound: false, preview });
168→    },
169→    [job.conversation?.messages],
170→  );
171→
172→  const handleDeleteRound = useCallback(
173→    (messageId: string) => {
174→      const msg = job.conversation?.messages.find((m) => m.id === messageId);
175→      const preview =
176→        msg?.blocks
177→          .map((b) => ("text" in b ? b.text : b.type))
178→          .join(" ")
179→          .slice(0, 200) ?? messageId;
180→      setDeleteDialog({ messageId, isRound: true, preview });
181→    },
182→    [job.conversation?.messages],
183→  );
184→
185→  const handleConfirmDelete = useCallback(
186→    async (reason?: string) => {
187→      if (!deleteDialog) return;
188→      const { messageId, isRound } = deleteDialog;
189→      setDeleteDialog(null);
190→      if (isRound) {
191→        const result = await deletion.deleteRound(messageId, reason);
192→        deletionToast.showDeletedToast(messageId, true, result.length);
193→      } else {
194→        await deletion.deleteMessage(messageId, reason);
195→        deletionToast.showDeletedToast(messageId, false);
196→      }
197→    },
198→    [deleteDialog, deletion, deletionToast],
199→  );
200→
201→  const handleUndoDelete = useCallback(async () => {
202→    if (!deletionToast.toast) return;
203→    await deletion.restoreMessage(deletionToast.toast.messageId);
204→    deletionToast.dismissToast();
205→  }, [deletion, deletionToast]);
206→
207→  const mergedRef = useCallback(
208→    (node: HTMLElement | null) => {
209→      (
210→        session.sectionRef as React.MutableRefObject<HTMLElement | null>
211→      ).current = node;
212→      (
213→        popover.containerRef as React.MutableRefObject<HTMLElement | null>
214→      ).current = node;
215→    },
216→    [session.sectionRef, popover.containerRef],
217→  );
218→
219→  const artifact =
220→    view === "reader"
221→      ? ""
222→      : (job.artifacts?.[view] ?? "Artefakt ist noch nicht verfügbar.");
223→  // Design-Entscheidung: Downloads erfolgen aus `displayedMarkdown`, das
224→  // `applyMarkdownRules` inklusive format_profile-Rules enthält. Der Server-
225→  // Endpoint `imports.exportArtifact` liefert hingegen rohe Artefakte ohne Rules.
226→  const displayedMarkdown = useMemo(() => {
227→    if (view !== "markdown") return artifact;
228→    try {
229→      return applyMarkdownRules(artifact, rules.activeRules);
230→    } catch {
231→      return artifact;
232→    }
233→  }, [artifact, rules.activeRules, view]);
234→
235→  const resolvedConversation = useMemo(() => {
236→    if (!job.conversation) return undefined;
237→    return {
238→      ...job.conversation,
239→      messages: resolvedMessages.map((rm) => ({
240→        id: rm.id,
241→        role: rm.role,
242→        blocks: rm.blocks,
243→      })),
244→    };
245→  }, [job.conversation, resolvedMessages]);
246→
247→  const readerEffectsMap = useMemo(
248→    () =>
249→      view === "reader" && resolvedConversation
250→        ? buildReaderEffectsMap(rules.activeRules, resolvedConversation)
251→        : new Map(),
252→    [rules.activeRules, resolvedConversation, view],
253→  );
254→
255→  const handleCopyMessage = useCallback(
256→    (messageId: string) => {
257→      const msg = resolvedConversation?.messages.find(
258→        (m) => m.id === messageId,
259→      );
260→      if (!msg) return;
261→      void copyMessageToClipboard(msg, view, msg.blocks);
262→    },
263→    [resolvedConversation, view],
264→  );
265→
266→  const [copySuccess, setCopySuccess] = useState(false);
267→  const copyTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
268→
269→  const handleCopyAll = useMemo(() => {
270→    const plugin = clientFormatRegistry.get(view);
271→    if (!plugin) return undefined;
272→
273→    const doCopy = async (content: string, isHtml: boolean) => {
274→      try {
275→        if (isHtml) {
276→          const blob = new Blob([content], { type: "text/html" });
277→          const plainBlob = new Blob([content], { type: "text/plain" });
278→          await navigator.clipboard.write([
279→            new ClipboardItem({
280→              "text/html": blob,
281→              "text/plain": plainBlob,
282→            }),
283→          ]);
284→        } else {
285→          await navigator.clipboard.writeText(content);
286→        }
287→        clearTimeout(copyTimeoutRef.current);
288→        setCopySuccess(true);
289→        copyTimeoutRef.current = setTimeout(() => setCopySuccess(false), 2000);
290→      } catch {
291→        // Fallback: silently fail
292→      }
293→    };
294→
295→    // Reader: special logic with buildReaderHtml
296→    if (view === "reader" && resolvedConversation) {
297→      return () => {
298→        const html = buildReaderHtml(
299→          resolvedConversation,
300→          readerEffectsMap,
301→          resolvedConversation.title ?? `export-${job.id}`,
302→        );
303→        void doCopy(html, true);
304→      };
305→    }
306→
307→    // Markdown: displayedMarkdown already has rules applied
308→    if (view === "markdown") {
309→      return () => {
310→        void doCopy(displayedMarkdown, false);
311→      };
312→    }
313→
314→    // Others: raw artifact
315→    if (artifact) {
316→      return () => {
317→        void doCopy(artifact, false);
318→      };
319→    }
320→    return undefined;
321→  }, [
322→    view,
323→    displayedMarkdown,
324→    job.id,
325→    resolvedConversation,
326→    readerEffectsMap,
327→    artifact,
328→  ]);
329→
330→  const handleDownload = useMemo(() => {
331→    const plugin = clientFormatRegistry.get(view);
332→    if (!plugin) return undefined;
333→
334→    // Reader has special download logic (needs effectsMap, conversation)
335→    if (view === "reader" && resolvedConversation) {
336→      return () => {
337→        const html = buildReaderHtml(
338→          resolvedConversation,
339→          readerEffectsMap,
340→          resolvedConversation.title ?? `export-${job.id}`,
341→        );
342→        downloadBlob(
343→          html,
344→          plugin.descriptor.exportMimeType,
345→          `export-${job.id}${plugin.descriptor.exportExtension}`,
346→        );
347→      };
348→    }
349→
350→    // For all other formats: use prepareDownload if available, else raw content
351→    const content = view === "markdown" ? displayedMarkdown : artifact;
352→    if (!content) return undefined;
353→
354→    return () => {
355→      const finalContent =
356→        plugin.prepareDownload?.(content, rules.activeRules) ?? content;
357→      downloadBlob(
358→        finalContent,
359→        plugin.descriptor.exportMimeType,
360→        `export-${job.id}${plugin.descriptor.exportExtension}`,
361→      );
362→    };
363→  }, [
364→    view,
365→    displayedMarkdown,
366→    job.id,
367→    resolvedConversation,
368→    readerEffectsMap,
369→    artifact,
370→    rules.activeRules,
371→  ]);
372→  const showPopover =
373→    session.adjustModeEnabled &&
374→    Boolean(session.activeSelection) &&
375→    Boolean(session.activeAnchor);
376→
377→  const popoverCallbacksRef = useRef({
378→    handleDiscardSession: session.handleDiscardSession,
379→    activeSessionDetail: session.activeSessionDetail,
380→    handleRejectLastChange: rules.handleRejectLastChange,
381→    setReplyVisible: session.setReplyVisible,
382→  });
383→  popoverCallbacksRef.current = {
384→    handleDiscardSession: session.handleDiscardSession,
385→    activeSessionDetail: session.activeSessionDetail,
386→    handleRejectLastChange: rules.handleRejectLastChange,
387→    setReplyVisible: session.setReplyVisible,
388→  };
389→
390→  const handlePopoverClose = useCallback(() => {
391→    popoverCallbacksRef.current.handleDiscardSession();
392→  }, []);
393→
394→  const handleRejectLastChange = useCallback(() => {
395→    const {
396→      activeSessionDetail,
397→      handleRejectLastChange: reject,
398→      setReplyVisible,
399→    } = popoverCallbacksRef.current;
400→    if (activeSessionDetail) {
401→      void reject(activeSessionDetail).then((success) => {
402→        if (success) setReplyVisible(false);
403→      });
404→    }
405→  }, []);
406→
407→  const sessionError =
408→    session.activeSessionError ?? rules.disableError ?? rules.promoteError;
409→
410→  const viewErrorFallback = (_error: Error, reset: () => void) => (
411→    <div className="flex flex-col items-center justify-center gap-4 p-8 text-center">
412→      <p className="text-red-700">{miscLabels.viewLoadError}</p>
413→      <button
414→        className="rounded-lg border border-border px-4 py-2 text-sm hover:bg-foreground/5"
415→        type="button"
416→        onClick={reset}
417→      >
418→        {miscLabels.retryButton}
419→      </button>
420→    </div>
421→  );
422→
423→  return (
424→    <section
425→      ref={mergedRef}
426→      className="relative space-y-4 rounded-[1.9rem] border border-border/80 bg-background/70 p-4 sm:p-5"
427→    >
428→      <StatusHeader
429→        activeStage={activeStage}
430→        elapsedTime={elapsedTime}
431→        job={job}
432→      />
433→
434→      {job.warnings.length > 0 ? (
435→        <div className="rounded-2xl border border-amber-300/40 bg-amber-100/60 px-4 py-3 text-sm text-amber-950">
436→          {job.warnings[0]}
437→        </div>
438→      ) : null}
439→
440→      {job.status === "failed" ? (
441→        <div className="rounded-2xl border border-red-300/40 bg-red-100/70 p-4 text-red-900">
442→          <p className="font-medium">{miscLabels.importFailed}</p>
443→          {job.errorStage && job.errorStage !== "done" && (
444→            <p className="text-sm mt-1">
445→              {miscLabels.errorInPhase(getImportStageLabel(job.errorStage))}
446→            </p>
447→          )}
448→          {job.error && <p className="text-sm mt-1">{job.error}</p>}
449→        </div>
450→      ) : job.status === "queued" || job.status === "running" ? (
451→        <LoadingStateBlock stageDetail={activeStage?.detail} />
452→      ) : (
453→        <div className="space-y-4">
454→          <CompletedToolbar
455→            adjustModeEnabled={session.adjustModeEnabled}
456→            copySuccess={copySuccess}
457→            editMode={editMode}
458→            isAdjustableView={isAdjustableView}
459→            rules={rules}
460→            view={view}
461→            onCopyAll={handleCopyAll}
462→            onDownloadMarkdown={handleDownload}
463→            onEditModeChange={handleEditModeChange}
464→            onToggleAdjustMode={handleToggleAdjustMode}
465→            onViewChange={onViewChange}
466→            deletionsCount={deletion.deletionsCount}
467→            showDeleted={deletion.showDeleted}
468→            snapshotCount={snapshots.snapshots.length}
469→            onVersionsClick={() => setVersionsModalOpen(true)}
470→            onToggleShowDeleted={() =>
471→              deletion.setShowDeleted(!deletion.showDeleted)
472→            }
473→          />
474→
475→          {sessionError && !session.adjustModeEnabled ? (
476→            <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
477→              {sessionError}
478→            </div>
479→          ) : null}
480→
481→          {view === "reader" ? (
482→            <ErrorBoundary fallback={viewErrorFallback}>
483→              <div className="space-y-2">
484→                <div className="flex justify-end">
485→                  <SaveIndicator
486→                    isSaving={messageEdits.isSaving}
487→                    hasEdits={hasEdits}
488→                  />
489→                </div>
490→                <ReaderView
491→                  activeRules={rules.activeRules}
492→                  conversation={resolvedConversation}
493→                  adjustModeEnabled={session.adjustModeEnabled}
494→                  editMode={editMode === "edit"}
495→                  effectsMap={readerEffectsMap}
496→                  highlightedRuleId={rules.hoveredRuleId}
497→                  selectedBlock={
498→                    view === "reader" ? session.activeSelection : null
499→                  }
500→                  onSelectBlock={session.handleSelectionChange}
501→                  deletedMessageIds={deletion.deletedMessageIds}
502→                  showDeleted={deletion.showDeleted}
503→                  onBlocksChange={handleBlocksChange}
504→                  onCopyMessage={handleCopyMessage}
505→                  onDeleteMessage={handleDeleteMessage}
506→                  onDeleteRound={handleDeleteRound}
507→                  onRestoreMessage={deletion.restoreMessage}
508→                />
509→              </div>
510→            </ErrorBoundary>
511→          ) : view === "markdown" ? (
512→            <ErrorBoundary fallback={viewErrorFallback}>
513→              <MarkdownView
514→                activeRules={rules.activeRules}
515→                content={displayedMarkdown}
516→                adjustModeEnabled={session.adjustModeEnabled}
517→                highlightedRuleId={rules.hoveredRuleId}
518→                selectedRange={session.activeSelection}
519→                onSelectLines={session.handleSelectionChange}
520→              />
521→            </ErrorBoundary>
522→          ) : (
523→            <ErrorBoundary fallback={viewErrorFallback}>
524→              <ArtifactView content={artifact} />
525→            </ErrorBoundary>
526→          )}
527→
528→          {session.showGuide ? (
529→            <AdjustmentModeGuide
530→              view={view}
531→              onDismiss={() => session.setGuideDismissed(true)}
532→            />
533→          ) : null}
534→
535→          <ErrorBoundary
536→            fallback={
537→              <div className="rounded-2xl border border-red-300/40 bg-red-100/70 px-4 py-3 text-sm text-red-900">
538→                {miscLabels.adjustmentLoadError}
539→              </div>
540→            }
541→          >
542→            <AdjustmentPopover
543→              anchor={session.activeAnchor ?? null}
544→              containerRef={session.sectionRef}
545→              draftMessage={session.activeDraftMessage}
546→              error={session.activeSessionError}
547→              isLoading={session.activeSessionLoading || session.isDiscarding}
548→              isSubmitting={session.isSubmitting}
549→              open={
550→                showPopover &&
551→                Boolean(session.activeSelection) &&
552→                Boolean(session.activeAnchor)
553→              }
554→              sessionDetail={session.activeSessionDetail}
555→              showReply={session.replyVisible}
556→              view={view}
557→              onClose={handlePopoverClose}
558→              onDraftMessageChange={session.handleDraftMessageChange}
559→              onRejectLastChange={handleRejectLastChange}
560→              onSubmitMessage={session.handleSubmitMessage}
561→            />
562→          </ErrorBoundary>
563→        </div>
564→      )}
565→
566→      {deleteDialog && (
567→        <DeleteMessageDialog
568→          messagePreview={deleteDialog.preview}
569→          isRound={deleteDialog.isRound}
570→          onConfirm={(reason) => {
571→            void handleConfirmDelete(reason);
572→          }}
573→          onCancel={() => setDeleteDialog(null)}
574→        />
575→      )}
576→
577→      {deletionToast.toast && (
578→        <UndoToast
579→          message={deletionToast.toast.message}
580→          onUndo={() => {
581→            void handleUndoDelete();
582→          }}
583→          onDismiss={deletionToast.dismissToast}
584→        />
585→      )}
586→
587→      <VersionsModal
588→        open={versionsModalOpen}
589→        onOpenChange={setVersionsModalOpen}
590→        snapshots={snapshots.snapshots}
591→        activeSnapshotId={snapshots.activeSnapshot?.id ?? null}
592→        onActivate={(snapshotId) => {
593→          void snapshots.activate(snapshotId);
594→        }}
595→        onDeactivate={() => {
596→          void snapshots.deactivate();
597→        }}
598→        onCreate={(label) => {
599→          void snapshots.create(label);
600→        }}
601→        onRename={(snapshotId, label) => {
602→          void snapshots.rename(snapshotId, label);
603→        }}
604→        onDelete={(snapshotId) => {
605→          void snapshots.delete(snapshotId);
606→        }}
607→      />
608→    </section>
609→  );
610→}
