 1→import type {
 2→  AdjustmentTargetFormat,
 3→  AdjustmentSelection as SharedAdjustmentSelection,
 4→} from "@chat-exporter/shared";
 5→import { defaultRegistry } from "@chat-exporter/shared";
 6→
 7→export type ViewMode = Extract<
 8→  AdjustmentTargetFormat,
 9→  "reader" | "markdown" | "handover" | "json"
10→>;
11→
12→export type AdjustmentSelection = SharedAdjustmentSelection;
13→
14→/**
15→ * Viewport-relative anchor coordinates as returned by `getBoundingClientRect()`.
16→ * Produced by child views (`ReaderView`, `MarkdownView`) and converted to
17→ * `FloatingAdjustmentAnchor` (container-relative) in `FormatWorkspace`.
18→ */
19→export type ViewportAnchor = {
20→  bottom: number;
21→  height: number;
22→  left: number;
23→  top: number;
24→  width: number;
25→};
26→
27→/**
28→ * Anchor coordinates for the floating adjustment popover.
29→ * All positional values (`top`, `bottom`, `left`) are **container-relative**,
30→ * i.e. relative to the `<section>` element rendered by `FormatWorkspace`,
31→ * not to the viewport.
32→ */
33→export type FloatingAdjustmentAnchor = {
34→  bottom: number;
35→  height: number;
36→  left: number;
37→  top: number;
38→  width: number;
39→};
40→
41→export type EditMode = "view" | "edit" | "adjust";
42→
43→export const adjustableViews = new Set(
44→  defaultRegistry.getAdjustable().map((f) => f.id),
45→);
